import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ===== Edge cases / simplest =====
  it.todo("empty item list yields premium of 5 G (only processing fee)");

  // ===== Base premiums for main items =====
  it.todo("quote for a single plain sword yields 105 G (100 base + 10 first insurance - 15 follow-up + 5 fee... wait single quote = 100 + 10 + 5 = 115)");
  it.todo("quote for a single plain sword (newcomer, first contract) yields 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("quote for a single plain amulet (newcomer, first contract) yields 71 G (60 base + 6 first insurance + 5 fee)");
  it.todo("quote for a single plain staff (newcomer, first contract) yields 93 G (80 base + 8 first insurance + 5 fee)");
  it.todo("quote for a single plain potion (newcomer, first contract) yields 49 G (40 base + 4 first insurance + 5 fee)");

  // ===== Components and building blocks =====
  it.todo("2 runes yield 50 G base premium (no block)");
  it.todo("3 runes yield 60 G base premium (block applies)");
  it.todo("4 runes yield 100 G base premium (no block - block requires exactly 3)");
  it.todo("7 runes yield 175 G base premium (no block formation)");
  it.todo("2 runes + 1 moonstone yield 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones yield 120 G base premium (two separate blocks)");

  // ===== Premium modifiers in isolation =====
  it.todo("cursed item adds 50% surcharge on item base premium");
  it.todo("highly enchanted item (enchantment >= 5) adds 30% surcharge on item base premium");
  it.todo("sword with exactly enchantment 5 triggers high-enchantment surcharge");
  it.todo("sword with enchantment 4 does not trigger high-enchantment surcharge");
  it.todo("sword with exactly enchantment 5 and cursed triggers both surcharges");
  it.todo("long-standing customer (>= 2 years) receives 20% loyalty discount on policy");
  it.todo("customer with exactly 2 years receives loyalty discount");
  it.todo("first insurance carries 10% initial assessment surcharge per item");
  it.todo("each contract after first receives 15% follow-up discount on policy");

  // ===== Modifier scope on multi-item policies =====
  it.todo("policy with cursed sword and plain amulet — cursed surcharge applies to cursed sword's base only — 215 G (100+60+50 +16 first insurance fee... let me recompute: base 160, curse adds 50 from sword = 210, +10% first insurance on 160 = 16; 210+16+5 = 231? Re-check spec)");
  it.todo("policy with cursed sword (100) and plain amulet (60) — base 160 + 50 curse = 210 before further modifiers and fee (per spec)");

  // ===== Rounding =====
  it.todo("premium calculation yielding 197.5 G rounds up to 198 G (in MHPCO's favor)");
  it.todo("payout calculation yielding 350.5 G rounds down to 350 G (in MHPCO's favor)");

  // ===== Integration example: Newcomer with cursed sword =====
  it.todo("newcomer (0 years, no prior contract) with cursed sword (steel, ench 3) — premium 165 G");

  // ===== Integration example: Long-standing customer's second contract =====
  it.todo("3-year customer's second quote with cursed sword (steel, ench 7) — premium 160 G");

  // ===== Claim processing: standard reimbursement =====
  it.todo("regular sword (steel, enchantment 3), damage 500 G — payout 400 G (deductible)");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G — payout 100 G (deductible, no special clause)");

  // ===== Claim processing: special clauses =====
  it.todo("dragon-material sword, enchantment 5, damage 800 G — payout 700 G (dragon full, then deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G — payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword with exactly enchantment 8, damage 1000 G — payout 400 G (50% applies, then deductible)");

  // ===== Deductible per damage event =====
  it.todo("dragon attack damages sword (500 G) and amulet (300 G); payout 600 G (deductible once per damaged item)");

  // ===== Multiple items of same type =====
  it.todo("policy covers two swords — insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damages both swords (two sword damage entries) — each treated separately with own deductible");
  it.todo("damages array contains more entries of a type than policy covers — CLI exits non-zero");

  // ===== Cap exhaustion =====
  it.todo("policy covers sword + amulet — insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword (modified premium 165 G) — cap stays at 2000 G (based on unmodified insurance value)");
  it.todo("policy covers sword + 3 runes (block) — insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword insured (cap 2000 G); two successive 1500 G claims — first payout 1400, then 600 (cap remaining 600 then 0)");

  // ===== Error cases =====
  it.todo("quote with unknown item type (e.g. broomstick) — CLI exits non-zero with stderr error");
  it.todo("claim references damage entry whose item is not in policy — CLI exits non-zero with stderr");
  it.todo("claim references damage with unknown item type — CLI exits non-zero with stderr");
  it.todo("claim contains damage entry with negative amount — CLI exits non-zero with stderr");

  // ===== Multi-step scenario (CLI / processScenario) =====
  it.todo("scenario with quote then claim — claim references policy by step index");
  it.todo("scenario schema example — quote amulet then claim 200 G — returns premium and payout/remainingCap");
});

