  it.todo("steel sword, ench 9, damage 1000 G — payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, exact ench 8, damage 1000 G — payout 400 G (50% applies, then deductible)");

  // ===== Deductible per damage event =====
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) — payout 600 G (deductible per item)");

  // ===== Multiple items of same type =====
  it.todo("policy covers 2 swords — insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damages both swords (two sword damages) — each with own deductible");
  it.todo("claim with more damage entries of a type than insured — CLI exits non-zero");

  // ===== Cap exhaustion =====
  it.todo("policy with sword + amulet — insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword — cap stays at 2000 G (based on unmodified insurance value)");
  it.todo("policy with sword + 3 runes (block) — insurance sum 1750 G (block discount affects premium only)");
