import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ===== Edge cases / simplest =====
  it("empty item list yields premium of 5 G (only processing fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // ===== Base premiums for main items (newcomer, first contract) =====
  it("quote for plain sword (newcomer) — premium 115 G (100 base + 10 first insurance + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote for plain amulet (newcomer) — premium 71 G (60 base + 6 first insurance + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote for plain staff (newcomer) — premium 93 G (80 base + 8 first insurance + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff", material: "oak", enchantment: 1, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote for plain potion (newcomer) — premium 49 G (40 base + 4 first insurance + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // ===== Components and building blocks =====
  it("2 runes yield 50 G base premium (no block) — total 60 G for newcomer (50 base + 5 first insurance + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes yield 60 G base premium (block of 3 alike applies) — total 71 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes yield 100 G base premium (no block — block requires exactly 3) — total 115 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes yield 175 G base premium (no block formation) — total 198 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("2 runes + 1 moonstone yield 75 G base premium (no block: different types) — total 88 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones yield 120 G base premium (two separate blocks) — total 137 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{
        op: "quote",
        items: [
          { type: "rune" }, { type: "rune" }, { type: "rune" },
          { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
        ],
      }],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // ===== Premium modifiers — thresholds and isolation =====
  it("cursed sword (newcomer) adds 50% surcharge — 165 G (100 + 50 curse + 10 first insurance + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }] }],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword with exactly enchantment 5 triggers high-enchantment surcharge — 145 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it.todo("sword with enchantment 4 does not trigger high-enchantment surcharge");
  it.todo("cursed sword with exactly enchantment 5 triggers both surcharges");
  it.todo("customer with exactly 2 years receives 20% loyalty discount");
  it.todo("each item in a quote is treated as first insurance (10% surcharge applies even on follow-up contracts)");

  // ===== Modifier scope on multi-item policies =====
  it.todo("cursed sword + plain amulet — base 160 G + 50 G curse = 210 G before policy modifiers and fee");

  // ===== Rounding (MHPCO's favor) =====
  it.todo("premium calculation yielding 197.5 G rounds up to 198 G");
  it.todo("payout calculation yielding 350.5 G rounds down to 350 G");

  // ===== Integration: newcomer with cursed sword =====
  it.todo("newcomer (0 years), cursed sword (steel, ench 3) — premium 165 G");

  // ===== Integration: long-standing customer's second contract =====
  it.todo("3-year customer's 2nd quote, cursed sword (steel, ench 7) — premium 160 G");

  // ===== Claim processing: standard reimbursement =====
  it.todo("regular sword (steel, ench 3), damage 500 G — payout 400 G (full minus deductible)");
  it.todo("rune damage 200 G — payout 100 G (full minus deductible, no special clause)");

  // ===== Claim processing: special clauses =====
  it.todo("dragon-material sword, ench 5, damage 800 G — payout 700 G (dragon full, then deductible)");
  it.todo("steel sword, ench 9, damage 1000 G — payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, exact ench 8, damage 1000 G — payout 400 G (50% applies, then deductible)");

  // ===== Deductible per damage event =====
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) — payout 600 G (deductible per item)");

  // ===== Multiple items of same type =====
  it.todo("policy covers 2 swords — insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damages both swords (two sword damages) — each with own deductible");
  it.todo("claim with more damage entries of a type than insured — CLI exits non-zero");

  // ===== Cap exhaustion =====
  it.todo("policy with sword + amulet — insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword — cap stays at 2000 G (based on unmodified insurance value)");
  it.todo("policy with sword + 3 runes (block) — insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword cap 2000 G, two successive 1500 G claims — payouts 1400 G then 600 G; remainingCap 600 then 0");

  // ===== Error cases =====
  it.todo("quote with unknown item type — CLI exits non-zero, stderr error, no results");
  it.todo("claim references damage for item not in policy — CLI exits non-zero with stderr");
  it.todo("claim damage with negative amount — CLI exits non-zero with stderr");

  // ===== Multi-step scenario =====
  it.todo("scenario: quote then claim referencing it by step index — returns both results in order");
});

