const premiumFor = (totalBase: number, totalSurcharge: number): number =>
  totalBase + totalSurcharge + Math.ceil(totalBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return groups;
};

const formsCompleteBlock = (type: string, group: Item[]): boolean =>
  COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE;

const baseForGroup = (type: string, group: Item[]): number =>
  formsCompleteBlock(type, group) ? BLOCK_BASE_PREMIUM : sumBy(group, baseFor);

const totalBaseFor = (items: Item[]): number =>
  Array.from(groupByType(items)).reduce(
    (total, [type, group]) => total + baseForGroup(type, group),
    0,
  );

const quoteFor = ({ items }: QuoteStep): QuoteResult => ({
  premium: premiumFor(totalBaseFor(items), totalSurchargeFor(items)),
});

export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
  return { results: input.steps.map(quoteFor) };
};

