  });
  return { results };
};
```

After:
```typescript
export const processScenario = (input: Scenario): { results: QuoteResult[] } => ({
  results: input.steps.map((step, index) => quoteFor(step, input.customer, index > 0)),
});
```

**Pre/Post Deltas (function `processScenario`)**:
- ESLint smells: 0 → 0 (already clean, stayed clean)
- Cognitive complexity: not flagged in either (well below threshold)
- APP mass: 31 → 16 (-15, ~48% reduction — eliminated two assignments worth 12 mass and the intermediate `results` binding)
- McCabe cyclomatic: 1 → 1 (no decision points changed)

