type Item = { type: string; cursed?: boolean; enchantment?: number };
type QuoteStep = { op: "quote"; items: Item[] };
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: QuoteStep[] };
type QuoteResult = { premium: number };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const CURSE_RATE = 0.5;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const FOLLOW_UP_RATE = 0.15;

const sumBy = <T>(items: T[], f: (x: T) => number): number =>
  items.reduce((acc, x) => acc + f(x), 0);

const baseFor = (item: Item): number => ITEM_BASE_PREMIUMS[item.type];

const SURCHARGE_RULES: ReadonlyArray<{ applies: (item: Item) => boolean; rate: number }> = [
  { applies: (item) => item.cursed === true, rate: CURSE_RATE },
  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_RATE },
];

const surchargeFor = (item: Item): number => {
  const base = baseFor(item);
  return sumBy(SURCHARGE_RULES, (rule) => (rule.applies(item) ? base * rule.rate : 0));
};

const totalSurchargeFor = (items: Item[]): number => sumBy(items, surchargeFor);

const loyaltyDiscountFor = (customer: Customer, totalBase: number): number =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? totalBase * LOYALTY_RATE : 0;

const followUpDiscountFor = (isFollowUp: boolean, totalBase: number): number =>
  isFollowUp ? totalBase * FOLLOW_UP_RATE : 0;

const premiumFor = (totalBase: number, totalSurcharge: number, customer: Customer, isFollowUp: boolean): number =>
  totalBase
  + totalSurcharge
  + Math.ceil(totalBase * FIRST_INSURANCE_RATE)
  - loyaltyDiscountFor(customer, totalBase)
  - followUpDiscountFor(isFollowUp, totalBase)
  + PROCESSING_FEE;

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return groups;
};

const formsCompleteBlock = (group: Item[]): boolean =>
  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(group[0].type);

