131	    invalid: (d, items) => !items.some((i) => i.type === d.itemType),
132	    message: (d) => `Claim references item type not in policy: ${d.itemType}`,
133	  },
134	];
135	
136	const countByKey = <T>(items: T[], key: (item: T) => string): Map<string, number> => {
137	  const counts = new Map<string, number>();
138	  for (const item of items) {
139	    const k = key(item);
140	    counts.set(k, (counts.get(k) ?? 0) + 1);
141	  }
142	  return counts;
143	};
144	
145	const findOverclaimedType = (damages: Damage[], items: Item[]): string | undefined => {
146	  const damageCounts = countByKey(damages, (d) => d.itemType);
147	  const itemCounts = countByKey(items, (i) => i.type);
148	  for (const [type, dc] of damageCounts) {
149	    if (dc > (itemCounts.get(type) ?? 0)) return type;
150	  }
151	  return undefined;
152	};
153	
154	const validateDamageCountsAgainstPolicy = (damages: Damage[], items: Item[]): void => {
155	  const type = findOverclaimedType(damages, items);
156	  if (type) throw new Error(`More damages of type ${type} than insured items`);
157	};
158	
159	const validateDamagesAgainstPolicy = (damages: Damage[], items: Item[]): void => {
160	  for (const rule of DAMAGE_VALIDATIONS) {
161	    const bad = damages.find((d) => rule.invalid(d, items));
162	    if (bad) throw new Error(rule.message(bad));
163	  }
164	  validateDamageCountsAgainstPolicy(damages, items);
165	};
166	
167	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
168	  validateDamagesAgainstPolicy(incident.damages, policy.items);
169	  const grossPayout = sumBy(incident.damages, (d) => payoutForDamage(d, policy.items));
170	  const payout = Math.floor(Math.min(grossPayout, policy.remainingCap));
171	  policy.remainingCap -= payout;
172	  return { payout, remainingCap: policy.remainingCap };
173	};
174	
175	const quoteFor = ({ items }: QuoteStep, ctx: QuoteContext): QuoteResult => ({
176	  premium: premiumFor(totalBaseFor(items), totalSurchargeFor(items), ctx),
177	});
178	
179	type ScenarioState = { customer: Customer; policies: Policy[]; quoteCount: number };
180	
181	const handleQuote = (step: QuoteStep, state: ScenarioState): QuoteResult => {
182	  const ctx: QuoteContext = { customer: state.customer, isFollowUp: state.quoteCount > 0 };
183	  state.quoteCount += 1;
184	  state.policies.push(newPolicy(step.items));
185	  return quoteFor(step, ctx);
186	};
187	
188	const handleStep = (step: Step, state: ScenarioState): StepResult =>
189	  step.op === "quote"
190	    ? handleQuote(step, state)
191	    : processClaim(state.policies[step.policy], step.incident);
192	
193	export const processScenario = (input: Scenario): { results: StepResult[] } => {
194	  const state: ScenarioState = { customer: input.customer, policies: [], quoteCount: 0 };
195	  const results = input.steps.map((step) => handleStep(step, state));
196	  return { results };
197	};

